from machine import Pin, ADC
import time
from umqtt.simple import MQTTClient

broker_ip = 'your_broker_ip'
client_id = 'esp32_client'
topic = 'sensors/temp'

# Setup ADC for temperature sensor (connected to GPIO 34)
temp_sensor = ADC(Pin(34))
temp_sensor.atten(ADC.ATTN_11DB)

def read_temperature():
    raw_value = temp_sensor.read()
    voltage = (raw_value / 4095) * 3.3  # Convert ADC value to voltage
    temperature = voltage * 100  # Example conversion to temperature in Celsius
    return temperature

client = MQTTClient(client_id, broker_ip)
client.connect()

try:
    while True:
        temperature = read_temperature()
        client.publish(topic, str(temperature))
        time.sleep(10)  # Publish every 10 seconds
except KeyboardInterrupt:
    client.disconnect()